import"./ticker-BxUDbM2L.js";import{i as e}from"./country-page-CK6BdUjw.js";/* empty css                  */import"./utils-Owvk3OYq.js";import"./breadcrumbs-CxxVGuAV.js";e({navDepth:2,breadcrumbParent:{label:"UAE Gold",url:"../../uae.html"},countryCode:"AE",currency:"AED",flag:"🇦🇪",nameEn:"Dubai, UAE",nameAr:"دبي، الإمارات",fixedPeg:!0,decimals:2,timezone:"Asia/Dubai",relatedCountries:[{file:"../../uae.html",nameEn:"UAE Overview",nameAr:"نظرة عامة — الإمارات",flag:"🇦🇪"},{file:"../../saudi-arabia.html",nameEn:"Saudi Arabia",nameAr:"السعودية",flag:"🇸🇦"},{file:"../../qatar.html",nameEn:"Qatar",nameAr:"قطر",flag:"🇶🇦"},{file:"../../kuwait.html",nameEn:"Kuwait",nameAr:"الكويت",flag:"🇰🇼"},{file:"../../bahrain.html",nameEn:"Bahrain",nameAr:"البحرين",flag:"🇧🇭"},{file:"../../oman.html",nameEn:"Oman",nameAr:"عُمان",flag:"🇴🇲"}],faqEn:[{q:"What is the gold price in Dubai today?",a:"The live gold price in Dubai is updated every 90 seconds. Dubai uses the UAE Dirham (AED) which is fixed at 3.6725 per USD. The price shown above reflects this live conversion. 22K per gram is the most commonly referenced retail benchmark."},{q:"Where is the cheapest place to buy gold in Dubai?",a:"The Dubai Gold Souk in Deira is typically the most price-competitive area because of the density of traders and the negotiation culture on making charges. However, the base metal price is standardised across all reputable dealers — it is the making charge and design premium that varies."},{q:"What karat should I buy in Dubai?",a:"22K is the standard for traditional jewellery and is the most widely available. 24K is best for investment bars and coins. 21K and 18K offer more design flexibility (mixed alloys allow more intricate designs). 18K is common in contemporary European-style jewellery."},{q:"Is gold in Dubai cheaper than elsewhere in the GCC?",a:"Dubai generally has very competitive gold prices due to low import duties, high trading volumes, and the AED peg to USD. However, the base spot price is the same across all GCC Dirham-pegged markets. The difference comes in making charges, VAT treatment, and retail overheads."},{q:"Can tourists buy gold in Dubai duty-free?",a:"Gold jewellery in Dubai is subject to 5% UAE VAT. However, investment gold (bars, coins meeting purity standards) is zero-rated for VAT. Tourists can claim VAT refunds on jewellery through the Planet/Global Blue scheme at Dubai Airport. Import rules in your home country apply separately."}],faqAr:[{q:"ما هو سعر الذهب في دبي اليوم؟",a:"يتم تحديث سعر الذهب في دبي كل 90 ثانية. يستخدم درهم الإمارات المرتبط بسعر ثابت 3.6725 درهم للدولار. السعر الموضح أعلاه يعكس هذا التحويل المباشر."},{q:"أين يمكن شراء الذهب بأرخص سعر في دبي؟",a:"سوق الذهب في ديرة هو الأكثر تنافسية عادةً بسبب كثافة التجار وإمكانية التفاوض على أجرة الصنعة. أما السعر الأساسي للمعدن فهو موحد لدى جميع التجار المعتمدين."},{q:"ما هو العيار الأفضل للشراء في دبي؟",a:"عيار 22 هو المعيار السائد للمجوهرات التقليدية والأكثر توفراً. عيار 24 الأنسب للسبائك والعملات الاستثمارية. عيار 18 شائع في المجوهرات المعاصرة."},{q:"هل الذهب في دبي أرخص من بقية دول الخليج؟",a:"دبي عموماً لديها أسعار ذهب تنافسية جداً بسبب انخفاض رسوم الاستيراد وحجم التداول الكبير. لكن سعر المعدن الأساسي موحد في جميع الدول المرتبطة بالدولار."},{q:"هل يمكن للسياح شراء الذهب بدون ضريبة في دبي؟",a:"المجوهرات الذهبية تخضع لضريبة القيمة المضافة 5% في الإمارات. أما الذهب الاستثماري (السبائك والعملات) فهو معفى منها. يمكن للسياح استرداد ضريبة القيمة المضافة على المجوهرات عبر مطار دبي."}]});
